// metrics_exporter.c
#include "memory_pool.h"
#include <prometheus.h>
void export_pool_metrics(MemoryPool* pool) {
PoolStats stats;
pool_get_stats(pool, &stats);  // Thread-safe snapshot
prom_gauge_set(pool_allocated_gauge, stats.allocated);
prom_gauge_set(pool_free_gauge, stats.free);
prom_gauge_set(pool_capacity_gauge, stats.total_blocks);
prom_gauge_set(pool_chunks_gauge, stats.chunk_count);
prom_gauge_set(pool_bytes_gauge, stats.total_bytes);
prom_gauge_set(pool_overhead_gauge, stats.overhead_bytes);
}
// Called by Prometheus scraper every 15s
void metrics_handler(http_request* req) {
export_pool_metrics(&global_pool);
prom_http_export(req->response);
}
